#include <stdio.h>
#include <stdlib.h>

// Structure to represent each node of the binary tree
struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
};

// Function to create a new node
struct TreeNode* createNode(int x) {
    struct TreeNode* newNode = (struct TreeNode*)malloc(sizeof(struct TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = x;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to count total number of nodes in the binary tree
int countNodes(struct TreeNode* root) {
    if (root == NULL) {
        return 0;
    }
    return 1 + countNodes(root->left) + countNodes(root->right);
}

int main() {
    // Create binary tree
    struct TreeNode* root = createNode(1);
    root->left = createNode(2);
    root->right = createNode(3);
    root->left->left = createNode(4);
    root->left->right = createNode(5);
    root->right->left = createNode(6);

    // Get total number of nodes
    int totalNodes = countNodes(root);

    // Output the result
    printf("Total number of nodes in the Complete Binary Tree: %d\n", totalNodes);

    return 0;
}

